// ╔══════════════════════════════════════════════════════════════════════════╗
// ║ Deep-Loop Runtime — Fan-Out Cross-Lineage Merge                          ║
// ╠══════════════════════════════════════════════════════════════════════════╣
// ║ Input:  CLI args (--loop-type, --artifact-dir).                          ║
// ║ Output: JSON to stdout.                                                  ║
// ║ Exit:   0=ok, 1=script error, 3=input validation error.                 ║
// ║                                                                          ║
// ║ Reads every {artifact-dir}/lineages/{label}/ sub-packet and produces:   ║
// ║   research: deduplicated deep-research-findings-registry.json +          ║
// ║             fanout-attribution.md                                        ║
// ║   review:   severity-rollup deep-review-findings-registry.json           ║
// ║             (strongest-restriction: any lineage P0 → merged FAIL) +     ║
// ║             fanout-attribution.md                                        ║
// ╚══════════════════════════════════════════════════════════════════════════╝

'use strict';

const fs = require('node:fs');
const path = require('node:path');

// ─────────────────────────────────────────────────────────────────────────────
// 1. HELPERS
// ─────────────────────────────────────────────────────────────────────────────

function inputError(message) {
  const err = new Error(message);
  err.code = 'INPUT_VALIDATION';
  return err;
}

function jsonOut(payload) {
  process.stdout.write(`${JSON.stringify(payload)}\n`);
}

function parseArgs(argv = process.argv.slice(2)) {
  const args = {};
  for (let i = 0; i < argv.length; i += 1) {
    const token = argv[i];
    if (!token.startsWith('--')) {
      throw inputError(`Unexpected positional argument: ${token}`);
    }
    const key = token.slice(2).replace(/-([a-z])/g, (_, c) => c.toUpperCase());
    const next = argv[i + 1];
    if (next === undefined || next.startsWith('--')) {
      args[key] = true;
    } else {
      args[key] = next;
      i += 1;
    }
  }
  return args;
}

function ensureString(args, key) {
  if (!args[key] || typeof args[key] !== 'string') {
    throw inputError(`${key} is required`);
  }
  return args[key];
}

function tryReadJson(filePath) {
  if (!fs.existsSync(filePath)) return null;
  try {
    return JSON.parse(fs.readFileSync(filePath, 'utf8'));
  } catch {
    return null;
  }
}

function readStateLog(stateLogPath) {
  if (!fs.existsSync(stateLogPath)) return [];
  const lines = fs.readFileSync(stateLogPath, 'utf8').trim().split('\n').filter(Boolean);
  return lines.flatMap((line) => {
    try {
      return [JSON.parse(line)];
    } catch {
      return [];
    }
  });
}

// ─────────────────────────────────────────────────────────────────────────────
// 2. RESEARCH MERGE
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Merge research findings registries from all lineages.
 * Deduplicates by findingId; cross-model attribution via lineage labels.
 * Returns the merged registry object.
 */
function mergeResearchRegistries(lineageData) {
  const findingById = new Map();

  for (const { label, registry } of lineageData) {
    if (!registry || !Array.isArray(registry.keyFindings)) continue;
    for (const finding of registry.keyFindings) {
      const id = finding.id || finding.title;
      if (!id) continue;
      if (findingById.has(id)) {
        const existing = findingById.get(id);
        // Add this lineage as a contributing source
        if (!existing._lineages) existing._lineages = [];
        if (!existing._lineages.includes(label)) existing._lineages.push(label);
      } else {
        findingById.set(id, { ...finding, _lineages: [label] });
      }
    }
  }

  const mergedFindings = [...findingById.values()];
  const openQuestionsById = new Map();
  const resolvedQuestionsById = new Map();
  const ruledOutById = new Map();

  for (const { label, registry } of lineageData) {
    if (!registry) continue;
    for (const q of registry.openQuestions ?? []) {
      const id = q.id || q.question || q.text;
      if (!id) continue;
      if (!openQuestionsById.has(id)) openQuestionsById.set(id, { ...q, _lineages: [label] });
      else {
        const existing = openQuestionsById.get(id);
        if (!existing._lineages.includes(label)) existing._lineages.push(label);
      }
    }
    // Resolved questions are produced per-lineage by the research reducer but
    // were previously dropped here, under-reporting answered coverage in the
    // merged registry. Collect them with the same id/_lineages discipline.
    for (const q of registry.resolvedQuestions ?? []) {
      const id = q.id || q.question || q.text;
      if (!id) continue;
      if (!resolvedQuestionsById.has(id)) resolvedQuestionsById.set(id, { ...q, _lineages: [label] });
      else {
        const existing = resolvedQuestionsById.get(id);
        if (!existing._lineages.includes(label)) existing._lineages.push(label);
      }
    }
    for (const d of registry.ruledOutDirections ?? []) {
      const id = d.id || d.direction;
      if (!id) continue;
      if (!ruledOutById.has(id)) ruledOutById.set(id, { ...d, _lineages: [label] });
    }
  }

  const totalIters = lineageData.reduce((sum, { registry }) => {
    return sum + (registry?.metrics?.iterationsCompleted ?? 0);
  }, 0);

  const avgConvergence =
    lineageData.length > 0
      ? lineageData.reduce((sum, { registry }) => sum + (registry?.metrics?.convergenceScore ?? 0), 0) /
        lineageData.length
      : 0;

  return {
    mergedFrom: lineageData.map(({ label }) => label),
    openQuestions: [...openQuestionsById.values()],
    resolvedQuestions: [...resolvedQuestionsById.values()],
    keyFindings: mergedFindings,
    ruledOutDirections: [...ruledOutById.values()],
    metrics: {
      iterationsCompleted: totalIters,
      openQuestions: openQuestionsById.size,
      resolvedQuestions: resolvedQuestionsById.size,
      keyFindings: mergedFindings.length,
      convergenceScore: Math.round(avgConvergence * 1000) / 1000,
      coverageBySources: {},
    },
  };
}

// ─────────────────────────────────────────────────────────────────────────────
// 3. REVIEW MERGE  (strongest-restriction)
// ─────────────────────────────────────────────────────────────────────────────

const SEVERITY_RANK = { P0: 3, P1: 2, P2: 1 };

/**
 * Merge review findings registries with strongest-restriction severity rollup.
 * Any lineage with an active P0 finding causes the merged result to be FAIL.
 * Deduplication is by findingId; cross-lineage P0 wins if any lineage reports it.
 */
function mergeReviewRegistries(lineageData) {
  const findingById = new Map();

  for (const { label, registry } of lineageData) {
    if (!registry || !Array.isArray(registry.openFindings)) continue;
    for (const finding of registry.openFindings) {
      if (finding.status !== 'active') continue;
      const id = finding.findingId || finding.title;
      if (!id) continue;
      if (findingById.has(id)) {
        const existing = findingById.get(id);
        // Strongest-restriction: escalate to highest severity seen across lineages
        if ((SEVERITY_RANK[finding.severity] ?? 0) > (SEVERITY_RANK[existing.severity] ?? 0)) {
          findingById.set(id, { ...finding, _lineages: [...(existing._lineages || []), label] });
        } else {
          if (!existing._lineages.includes(label)) existing._lineages.push(label);
        }
      } else {
        findingById.set(id, { ...finding, _lineages: [label] });
      }
    }
  }

  // Resolved findings are tracked separately per lineage and were previously
  // dropped here, zeroing the merged resolved coverage. Collect them by id with
  // _lineages attribution, without touching open-finding/verdict semantics.
  const resolvedFindingById = new Map();
  for (const { label, registry } of lineageData) {
    if (!registry || !Array.isArray(registry.resolvedFindings)) continue;
    for (const finding of registry.resolvedFindings) {
      const id = finding.findingId || finding.title;
      if (!id) continue;
      if (resolvedFindingById.has(id)) {
        const existing = resolvedFindingById.get(id);
        if (!existing._lineages.includes(label)) existing._lineages.push(label);
      } else {
        resolvedFindingById.set(id, { ...finding, _lineages: [label] });
      }
    }
  }
  const mergedResolvedFindings = [...resolvedFindingById.values()];

  const mergedFindings = [...findingById.values()];
  const activeP0 = mergedFindings.filter((f) => f.severity === 'P0' && f.status === 'active').length;
  const activeP1 = mergedFindings.filter((f) => f.severity === 'P1' && f.status === 'active').length;
  const activeP2 = mergedFindings.filter((f) => f.severity === 'P2' && f.status === 'active').length;

  // Strongest-restriction verdict
  let mergedVerdict;
  if (activeP0 > 0) {
    mergedVerdict = 'FAIL';
  } else if (activeP1 > 0) {
    mergedVerdict = 'CONDITIONAL';
  } else {
    mergedVerdict = 'PASS';
  }

  return {
    mergedFrom: lineageData.map(({ label }) => label),
    mergedVerdict,
    openFindings: mergedFindings,
    resolvedFindings: mergedResolvedFindings,
    findingsBySeverity: { P0: activeP0, P1: activeP1, P2: activeP2 },
    openFindingsCount: mergedFindings.length,
    resolvedFindingsCount: mergedResolvedFindings.length,
    activeP0,
    activeP1,
    activeP2,
  };
}

// ─────────────────────────────────────────────────────────────────────────────
// 4. ATTRIBUTION
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Build fanout-attribution.md summarizing per-lineage convergence, iters, salvage, model.
 */
function buildAttributionMd(lineageData, loopType) {
  const lines = [
    `# Fan-Out Attribution`,
    ``,
    `Loop type: **${loopType}**  |  Lineage count: **${lineageData.length}**`,
    ``,
    `| Label | Kind | Model | Iterations | Convergence | Salvaged | Verdict |`,
    `|-------|------|-------|-----------|-------------|----------|---------|`,
  ];

  for (const { label, registry, stateRecords, kind, model } of lineageData) {
    const iters = stateRecords.filter((r) => r.type === 'iteration').length;
    const salvage = stateRecords.filter((r) => r.type === 'event' && r.event === 'salvaged_from_stdout').length;
    const convergenceScore = registry?.metrics?.convergenceScore ?? registry?.convergenceScore ?? 'n/a';
    const verdict =
      loopType === 'review'
        ? registry?.findingsBySeverity?.P0 > 0
          ? 'FAIL'
          : registry?.findingsBySeverity?.P1 > 0
          ? 'CONDITIONAL'
          : 'PASS'
        : 'n/a';
    lines.push(`| ${label} | ${kind ?? 'unknown'} | ${model ?? 'default'} | ${iters} | ${convergenceScore} | ${salvage} | ${verdict} |`);
  }

  lines.push('');
  return lines.join('\n');
}

// ─────────────────────────────────────────────────────────────────────────────
// 5. MAIN
// ─────────────────────────────────────────────────────────────────────────────

function main() {
  const args = parseArgs();
  const loopType = ensureString(args, 'loopType');
  if (loopType !== 'research' && loopType !== 'review' && loopType !== 'context') {
    throw inputError('loopType must be "research", "review", or "context"');
  }
  const artifactDir = ensureString(args, 'artifactDir');
  const lineagesDir = path.join(artifactDir, 'lineages');

  if (!fs.existsSync(lineagesDir)) {
    jsonOut({ status: 'ok', message: 'no lineages directory — nothing to merge', merged: 0 });
    return;
  }

  const labelDirs = fs.readdirSync(lineagesDir).filter((entry) =>
    fs.statSync(path.join(lineagesDir, entry)).isDirectory(),
  );

  if (labelDirs.length === 0) {
    jsonOut({ status: 'ok', message: 'no lineage subdirs found', merged: 0 });
    return;
  }

  // Load per-lineage data
  const registryName =
    loopType === 'review' ? 'deep-review-findings-registry.json' : 'deep-research-findings-registry.json';
  const stateLogName = loopType === 'review' ? 'deep-review-state.jsonl' : 'deep-research-state.jsonl';
  const summaryPath = path.join(artifactDir, 'orchestration-summary.json');
  const orchestrationSummary = tryReadJson(summaryPath) ?? {};

  const lineageData = labelDirs.map((label) => {
    const lineageDir = path.join(lineagesDir, label);
    const registry = tryReadJson(path.join(lineageDir, registryName));
    const stateRecords = readStateLog(path.join(lineageDir, stateLogName));
    // Infer kind/model from state log executor records
    const executorRecord = stateRecords.find((r) => r.type === 'event' && r.event === 'executor_start');
    return {
      label,
      lineageDir,
      registry,
      stateRecords,
      kind: executorRecord?.kind ?? orchestrationSummary?.[label]?.kind ?? 'unknown',
      model: executorRecord?.model ?? orchestrationSummary?.[label]?.model ?? 'unknown',
    };
  });

  const lineagesWithRegistry = lineageData.filter((d) => d.registry !== null);

  let mergedRegistry;
  if (loopType === 'review') {
    mergedRegistry = mergeReviewRegistries(lineagesWithRegistry);
  } else {
    mergedRegistry = mergeResearchRegistries(lineagesWithRegistry);
  }

  // Write merged registry to base artifact dir (replacing single-executor path)
  const mergedRegistryPath = path.join(artifactDir, registryName);
  fs.writeFileSync(mergedRegistryPath, JSON.stringify(mergedRegistry, null, 2), 'utf8');

  // Write attribution markdown
  const attributionPath = path.join(artifactDir, 'fanout-attribution.md');
  fs.writeFileSync(attributionPath, buildAttributionMd(lineageData, loopType), 'utf8');

  jsonOut({
    status: 'ok',
    loop_type: loopType,
    merged_lineages: lineagesWithRegistry.length,
    skipped_no_registry: lineageData.length - lineagesWithRegistry.length,
    merged_registry_path: mergedRegistryPath,
    attribution_path: attributionPath,
    ...(loopType === 'review'
      ? { merged_verdict: mergedRegistry.mergedVerdict, active_p0: mergedRegistry.activeP0, active_p1: mergedRegistry.activeP1 }
      : { key_findings: mergedRegistry.keyFindings?.length ?? 0 }),
  });
}

// Exports for unit testing
module.exports = { mergeResearchRegistries, mergeReviewRegistries, buildAttributionMd };

if (require.main === module) {
  try {
    main();
  } catch (err) {
    const code = err && err.code === 'INPUT_VALIDATION' ? 3 : 1;
    jsonOut({
      status: 'error',
      error: err instanceof Error ? err.message : String(err),
      code: err && err.code ? err.code : 'SCRIPT_ERROR',
    });
    if (code === 1) {
      process.stderr.write(
        JSON.stringify({ error: err instanceof Error ? err.message : String(err), stack: err && err.stack }) + '\n',
      );
    }
    process.exit(code);
  }
}

#!/usr/bin/env node

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║ Deep-Loop Runtime — Convergence Entrypoint                               ║
// ╠══════════════════════════════════════════════════════════════════════════╣
// ║ Input:  CLI args (--spec-folder, --loop-type, --session-id, optional     ║
// ║         --iteration, --persist-snapshot).                                ║
// ║ Output: JSON to stdout.                                                  ║
// ║ Exit:   0=ok, 1=script error, 2=DB error, 3=input validation error.     ║
// ╚══════════════════════════════════════════════════════════════════════════╝

'use strict';

// ─────────────────────────────────────────────────────────────────────────────
// 1. IMPORTS
// ─────────────────────────────────────────────────────────────────────────────

const fs = require('node:fs');
const path = require('node:path');
const { spawnSync } = require('node:child_process');

const {
  classifyExitCode,
  installSignalHandlers,
  maybeThrowTestFault,
  validateNamespaceValue,
} = require('./lib/cli-guards.cjs');

// ─────────────────────────────────────────────────────────────────────────────
// 2. CONSTANTS
// ─────────────────────────────────────────────────────────────────────────────

const TSX_LOADER = path.resolve(
  __dirname,
  '..',
  '..',
  'system-spec-kit',
  'scripts',
  'node_modules',
  'tsx',
  'dist',
  'loader.mjs',
);

// ─────────────────────────────────────────────────────────────────────────────
// 3. TSX BOOTSTRAP
// ─────────────────────────────────────────────────────────────────────────────

if (process.env.DEEP_LOOP_TSX_LOADED !== '1') {
  const child = spawnSync(
    process.execPath,
    ['--import', TSX_LOADER, __filename, ...process.argv.slice(2)],
    {
      cwd: process.cwd(),
      env: { ...process.env, DEEP_LOOP_TSX_LOADED: '1' },
      input: process.stdin.isTTY ? undefined : fs.readFileSync(0),
      encoding: 'utf8',
    },
  );
  if (child.stdout) process.stdout.write(child.stdout);
  if (child.stderr) process.stderr.write(child.stderr);
  process.exit(child.status === null ? 1 : child.status);
}

// ─────────────────────────────────────────────────────────────────────────────
// 4. HELPERS
// ─────────────────────────────────────────────────────────────────────────────

function parseArgs(argv = process.argv.slice(2)) {
  const args = {};
  for (let i = 0; i < argv.length; i += 1) {
    const token = argv[i];
    if (!token.startsWith('--')) {
      throw inputError(`Unexpected positional argument: ${token}`);
    }
    const key = token.slice(2).replace(/-([a-z])/g, (_, c) => c.toUpperCase());
    const next = argv[i + 1];
    if (next === undefined || next.startsWith('--')) {
      args[key] = true;
    } else {
      args[key] = next;
      i += 1;
    }
  }
  return args;
}

function inputError(message) {
  const err = new Error(message);
  err.code = 'INPUT_VALIDATION';
  return err;
}

function ensureString(args, key) {
  if (!args[key] || typeof args[key] !== 'string') {
    throw inputError(`${key} is required`);
  }
  return args[key];
}

function asBoolean(value) {
  return value === true || value === 'true' || value === '1';
}

function jsonOut(payload) {
  process.stdout.write(`${JSON.stringify(payload)}\n`);
}

function blockersCsv(blockers) {
  return blockers
    .filter((blocker) => blocker && blocker.severity === 'blocking')
    .map((blocker) => `${blocker.type}:${blocker.count}`)
    .join(',');
}

function computeCompositeScore(signals, loopType) {
  if (!signals || typeof signals !== 'object') return 0;
  const clamp = (value) => Math.max(0, Math.min(1, value));
  const safe = (value) => (typeof value === 'number' && Number.isFinite(value) ? value : 0);
  if (loopType === 'research') {
    const normalizedDiversity = Math.min(safe(signals.sourceDiversity) / 3.0, 1.0);
    const normalizedDepth = Math.min(safe(signals.evidenceDepth) / 5.0, 1.0);
    const invertedContradictions = 1.0 - clamp(safe(signals.contradictionDensity));
    const score =
      clamp(safe(signals.questionCoverage)) * 0.30 +
      clamp(safe(signals.claimVerificationRate)) * 0.25 +
      invertedContradictions * 0.15 +
      normalizedDiversity * 0.15 +
      normalizedDepth * 0.15;
    return Math.round(clamp(score) * 1000) / 1000;
  }
  if (loopType === 'context') {
    // REUSE catalog weighted highest (reuse-first principle); agreement second
    // (by-model confidence); then scope coverage, relevance gate, dependency map.
    const score =
      clamp(safe(signals.reuseCatalogCoverage)) * 0.30 +
      clamp(safe(signals.agreementRate)) * 0.25 +
      clamp(safe(signals.sliceCoverage)) * 0.20 +
      clamp(safe(signals.relevanceFloor)) * 0.15 +
      clamp(safe(signals.dependencyCompleteness)) * 0.10;
    return Math.round(clamp(score) * 1000) / 1000;
  }
  const score =
    clamp(safe(signals.dimensionCoverage)) * 0.25 +
    clamp(safe(signals.findingStability)) * 0.20 +
    clamp(safe(signals.p0ResolutionRate)) * 0.25 +
    clamp(safe(signals.evidenceDensity)) * 0.15 +
    clamp(safe(signals.hotspotSaturation)) * 0.15;
  return Math.round(clamp(score) * 1000) / 1000;
}

function parseMetadata(metadata) {
  return metadata && typeof metadata === 'object' ? metadata : {};
}

function buildReviewSignals(nodes, edges) {
  const dimensionIds = new Set(nodes.filter((node) => node.kind === 'DIMENSION').map((node) => node.id));
  const findingNodes = nodes.filter((node) => node.kind === 'FINDING');
  const fileNodes = nodes.filter((node) => node.kind === 'FILE');
  const coversEdges = edges.filter((edge) => edge.relation === 'COVERS');
  const contradictionEdges = edges.filter((edge) => edge.relation === 'CONTRADICTS');
  const evidenceEdges = edges.filter((edge) => edge.relation === 'EVIDENCE_FOR');
  const resolvesTargetIds = new Set(edges.filter((edge) => edge.relation === 'RESOLVES').map((edge) => edge.targetId));
  const coveredDimensionIds = new Set(
    coversEdges.map((edge) => edge.sourceId).filter((sourceId) => dimensionIds.has(sourceId)),
  );
  const contradictionNodeIds = new Set();
  for (const edge of contradictionEdges) {
    contradictionNodeIds.add(edge.sourceId);
    contradictionNodeIds.add(edge.targetId);
  }
  const p0Findings = findingNodes.filter((node) => parseMetadata(node.metadata).severity === 'P0');
  const hotspotFiles = fileNodes.filter((node) => {
    const hotspotScore = parseMetadata(node.metadata).hotspot_score;
    return typeof hotspotScore === 'number' && hotspotScore > 0;
  });
  let saturatedHotspots = 0;
  for (const file of hotspotFiles) {
    const coveringDimensions = new Set(
      coversEdges
        .filter((edge) => edge.targetId === file.id)
        .map((edge) => edge.sourceId)
        .filter((sourceId) => dimensionIds.has(sourceId)),
    );
    if (coveringDimensions.size >= 2) saturatedHotspots += 1;
  }
  return {
    dimensionCoverage: dimensionIds.size > 0 ? coveredDimensionIds.size / dimensionIds.size : 0,
    findingStability: findingNodes.length > 0
      ? findingNodes.filter((node) => !contradictionNodeIds.has(node.id)).length / findingNodes.length
      : 0,
    p0ResolutionRate: p0Findings.length > 0
      ? p0Findings.filter((node) => resolvesTargetIds.has(node.id)).length / p0Findings.length
      : 1,
    evidenceDensity: findingNodes.length > 0 ? evidenceEdges.length / findingNodes.length : 0,
    hotspotSaturation: hotspotFiles.length > 0 ? saturatedHotspots / hotspotFiles.length : 1,
  };
}

function evaluateResearch(signals, gaps, contradictions, unverified) {
  const thresholds = {
    questionCoverage: 0.7,
    claimVerificationRate: 0.6,
    contradictionDensity: 0.15,
    sourceDiversity: 1.5,
    evidenceDepth: 1.5,
  };
  const blockers = [];
  const trace = [
    { signal: 'questionCoverage', value: signals.questionCoverage, threshold: thresholds.questionCoverage, passed: signals.questionCoverage >= thresholds.questionCoverage, role: 'weighted' },
    { signal: 'claimVerificationRate', value: signals.claimVerificationRate, threshold: thresholds.claimVerificationRate, passed: signals.claimVerificationRate >= thresholds.claimVerificationRate, role: 'weighted' },
    { signal: 'contradictionDensity', value: signals.contradictionDensity, threshold: thresholds.contradictionDensity, passed: signals.contradictionDensity <= thresholds.contradictionDensity, role: 'weighted' },
    { signal: 'sourceDiversity', value: signals.sourceDiversity, threshold: thresholds.sourceDiversity, passed: signals.sourceDiversity >= thresholds.sourceDiversity, role: 'blocking_guard' },
    { signal: 'evidenceDepth', value: signals.evidenceDepth, threshold: thresholds.evidenceDepth, passed: signals.evidenceDepth >= thresholds.evidenceDepth, role: 'blocking_guard' },
  ];
  if (signals.sourceDiversity < thresholds.sourceDiversity) {
    blockers.push({ type: 'source_diversity_guard', description: `Source diversity (${signals.sourceDiversity.toFixed(2)}) is below the blocking threshold (${thresholds.sourceDiversity}). STOP is blocked until diverse sources cover key questions.`, count: 1, severity: 'blocking' });
  }
  if (signals.evidenceDepth < thresholds.evidenceDepth) {
    blockers.push({ type: 'evidence_depth_guard', description: `Evidence depth (${signals.evidenceDepth.toFixed(2)}) is below the blocking threshold (${thresholds.evidenceDepth}). STOP is blocked until question->finding->source chains are deeper.`, count: 1, severity: 'blocking' });
  }
  if (gaps.length > 0) {
    blockers.push({ type: 'uncovered_questions', description: `${gaps.length} question(s) have no coverage edges`, count: gaps.length, severity: signals.questionCoverage < thresholds.questionCoverage ? 'blocking' : 'warning' });
  }
  if (contradictions.length > 0 && signals.contradictionDensity > thresholds.contradictionDensity) {
    blockers.push({ type: 'high_contradiction_density', description: `${contradictions.length} contradiction(s) detected with density above threshold`, count: contradictions.length, severity: 'blocking' });
  }
  if (unverified.length > 0) {
    blockers.push({ type: 'unverified_claims', description: `${unverified.length} claim(s) remain unverified`, count: unverified.length, severity: signals.claimVerificationRate < thresholds.claimVerificationRate ? 'blocking' : 'warning' });
  }
  return { blockers, trace };
}

function evaluateReview(signals, gaps, contradictions) {
  const thresholds = {
    dimensionCoverage: 0.8,
    findingStability: 0.7,
    p0ResolutionRate: 0.9,
    evidenceDensity: 1.0,
    hotspotSaturation: 0.6,
  };
  const blockers = [];
  const trace = [
    { signal: 'dimensionCoverage', value: signals.dimensionCoverage, threshold: thresholds.dimensionCoverage, passed: signals.dimensionCoverage >= thresholds.dimensionCoverage, role: 'blocking_guard' },
    { signal: 'findingStability', value: signals.findingStability, threshold: thresholds.findingStability, passed: signals.findingStability >= thresholds.findingStability, role: 'weighted' },
    { signal: 'p0ResolutionRate', value: signals.p0ResolutionRate, threshold: thresholds.p0ResolutionRate, passed: signals.p0ResolutionRate >= thresholds.p0ResolutionRate, role: 'weighted' },
    { signal: 'evidenceDensity', value: signals.evidenceDensity, threshold: thresholds.evidenceDensity, passed: signals.evidenceDensity >= thresholds.evidenceDensity, role: 'weighted' },
    { signal: 'hotspotSaturation', value: signals.hotspotSaturation, threshold: thresholds.hotspotSaturation, passed: signals.hotspotSaturation >= thresholds.hotspotSaturation, role: 'weighted' },
  ];
  if (signals.p0ResolutionRate < thresholds.p0ResolutionRate) {
    blockers.push({ type: 'unresolved_p0_findings', description: `P0 resolution rate (${(signals.p0ResolutionRate * 100).toFixed(0)}%) is below threshold (${(thresholds.p0ResolutionRate * 100).toFixed(0)}%)`, count: 1, severity: 'blocking' });
  }
  if (signals.dimensionCoverage < thresholds.dimensionCoverage) {
    blockers.push({ type: 'uncovered_dimensions', description: `Dimension coverage (${(signals.dimensionCoverage * 100).toFixed(0)}%) is below threshold (${(thresholds.dimensionCoverage * 100).toFixed(0)}%). ${gaps.length} gap(s) found. STOP is blocked until all required dimensions have meaningful coverage.`, count: gaps.length, severity: 'blocking' });
  }
  if (contradictions.length > 0 && signals.findingStability < thresholds.findingStability) {
    blockers.push({ type: 'unstable_findings', description: `${contradictions.length} contradiction(s) are lowering finding stability below threshold`, count: contradictions.length, severity: 'blocking' });
  }
  return { blockers, trace };
}

function evaluateContext(signals, gaps, contradictions) {
  const thresholds = {
    sliceCoverage: 0.7,
    reuseCatalogCoverage: 0.6,
    agreementRate: 0.5,
    relevanceFloor: 0.5,
    dependencyCompleteness: 0.7,
  };
  const blockers = [];
  const trace = [
    { signal: 'sliceCoverage', value: signals.sliceCoverage, threshold: thresholds.sliceCoverage, passed: signals.sliceCoverage >= thresholds.sliceCoverage, role: 'blocking_guard' },
    { signal: 'reuseCatalogCoverage', value: signals.reuseCatalogCoverage, threshold: thresholds.reuseCatalogCoverage, passed: signals.reuseCatalogCoverage >= thresholds.reuseCatalogCoverage, role: 'weighted' },
    { signal: 'agreementRate', value: signals.agreementRate, threshold: thresholds.agreementRate, passed: signals.agreementRate >= thresholds.agreementRate, role: 'blocking_guard' },
    { signal: 'relevanceFloor', value: signals.relevanceFloor, threshold: thresholds.relevanceFloor, passed: signals.relevanceFloor >= thresholds.relevanceFloor, role: 'blocking_guard' },
    { signal: 'dependencyCompleteness', value: signals.dependencyCompleteness, threshold: thresholds.dependencyCompleteness, passed: signals.dependencyCompleteness >= thresholds.dependencyCompleteness, role: 'weighted' },
  ];
  if (signals.sliceCoverage < thresholds.sliceCoverage) {
    blockers.push({ type: 'uncovered_slices', description: `Slice coverage (${(signals.sliceCoverage * 100).toFixed(0)}%) is below threshold (${(thresholds.sliceCoverage * 100).toFixed(0)}%). ${gaps.length} gap(s) found. STOP is blocked until the in-scope surface is swept.`, count: gaps.length, severity: 'blocking' });
  }
  if (signals.relevanceFloor < thresholds.relevanceFloor) {
    blockers.push({ type: 'low_relevance_focus', description: `Relevance floor (${(signals.relevanceFloor * 100).toFixed(0)}%) is below threshold. The loop is collecting mostly low-relevance context; STOP is blocked until findings clear the relevance gate.`, count: 1, severity: 'blocking' });
  }
  if (signals.agreementRate < thresholds.agreementRate) {
    blockers.push({ type: 'low_cross_executor_agreement', description: `Cross-executor agreement (${(signals.agreementRate * 100).toFixed(0)}%) is below threshold. Findings are not yet confirmed by multiple model lenses; STOP is blocked.`, count: 1, severity: 'blocking' });
  }
  if (contradictions.length > 0) {
    blockers.push({ type: 'context_contradictions', description: `${contradictions.length} contradiction(s) detected across executors; reconcile before STOP.`, count: contradictions.length, severity: 'warning' });
  }
  return { blockers, trace };
}

function decisionReason(decision, blockingBlockers, trace) {
  if (decision === 'STOP_ALLOWED') return 'All convergence signals pass thresholds; STOP is allowed pending newInfoRatio agreement.';
  if (decision === 'STOP_BLOCKED') {
    return `STOP is blocked by ${blockingBlockers.length} blocker(s): ${blockingBlockers.map((blocker) => blocker.type).join(', ')}`;
  }
  return `Convergence signals not yet met: ${trace.filter((entry) => !entry.passed).map((entry) => entry.signal).join(', ')}. Continue iterating.`;
}

// ─────────────────────────────────────────────────────────────────────────────
// 5. CORE LOGIC
// ─────────────────────────────────────────────────────────────────────────────

async function main() {
  const args = parseArgs();
  const specFolder = validateNamespaceValue(ensureString(args, 'specFolder'), 'specFolder', inputError);
  const loopType = ensureString(args, 'loopType');
  const sessionId = validateNamespaceValue(ensureString(args, 'sessionId'), 'sessionId', inputError);
  if (loopType !== 'research' && loopType !== 'review' && loopType !== 'council' && loopType !== 'context') {
    throw inputError('loopType must be "research", "review", "council", or "context"');
  }

  const ns = { specFolder, loopType, sessionId };
  let db = null;

  try {
    const isCouncil = loopType === 'council';
    db = isCouncil
      ? await import('../lib/council/council-graph-db.ts')
      : await import('../lib/coverage-graph/coverage-graph-db.ts');
    installSignalHandlers(() => db?.closeDb());
    maybeThrowTestFault();
    if (isCouncil) {
      if (asBoolean(args.persistSnapshot) && !args.roundId) {
        throw inputError('--round-id is required when --persist-snapshot is true for council convergence');
      }
      const councilConvergence = require('../lib/council/convergence.cjs');
      const data = await councilConvergence.evaluateCouncilConvergence(ns, {
        roundId: args.roundId,
        persistSnapshot: asBoolean(args.persistSnapshot),
      });
      jsonOut(councilConvergence.bridgePayload(data));
      return;
    }

    const signalsLib = await import('../lib/coverage-graph/coverage-graph-signals.ts');
    const queryLib = await import('../lib/coverage-graph/coverage-graph-query.ts');
    const nodes = db.getNodes(ns);
    const edges = db.getEdges(ns);
    const snapshots = db.getSnapshots(specFolder, loopType, sessionId);
    const stats = {
      totalNodes: nodes.length,
      totalEdges: edges.length,
      nodesByKind: nodes.reduce((acc, node) => ({ ...acc, [node.kind]: (acc[node.kind] || 0) + 1 }), {}),
      edgesByRelation: edges.reduce((acc, edge) => ({ ...acc, [edge.relation]: (acc[edge.relation] || 0) + 1 }), {}),
      lastIteration: snapshots.length > 0 ? snapshots[snapshots.length - 1].iteration : null,
    };

    if (stats.totalNodes === 0) {
      const data = {
        decision: 'CONTINUE',
        reason: 'Graph is empty; insufficient data for convergence assessment',
        signals: null,
        blockers: [],
        trace: [],
        namespace: ns,
        scopeMode: 'session',
        nodeCount: 0,
        edgeCount: 0,
      };
      jsonOut({ status: 'ok', data, graph_decision: data.decision, graph_decision_json: JSON.stringify(data.decision), graph_signals_json: {}, graph_blockers_json: [], graph_blockers_csv: '', graph_stop_blocked: false, graph_trace_json: [], graph_convergence_score: 0 });
      return;
    }

    const signals = loopType === 'research'
      ? {
          questionCoverage: signalsLib.computeResearchQuestionCoverageFromData(nodes, edges),
          claimVerificationRate: signalsLib.computeResearchClaimVerificationRateFromData(nodes),
          contradictionDensity: signalsLib.computeResearchContradictionDensityFromData(edges),
          sourceDiversity: signalsLib.computeResearchSourceDiversityFromData(nodes, edges),
          evidenceDepth: signalsLib.computeResearchEvidenceDepthFromData(nodes, edges),
        }
      : loopType === 'context'
        ? signalsLib.computeContextSignalsFromData(nodes, edges)
        : buildReviewSignals(nodes, edges);
    const score = computeCompositeScore(signals, loopType);
    const signalsWithScore = { ...signals, score };
    const gaps = queryLib.findCoverageGaps(ns);
    const contradictions = queryLib.findContradictions(ns);
    const unverified = loopType === 'research' ? queryLib.findUnverifiedClaims(ns) : [];
    const evaluated = loopType === 'research'
      ? evaluateResearch(signals, gaps, contradictions, unverified)
      : loopType === 'context'
        ? evaluateContext(signals, gaps, contradictions)
        : evaluateReview(signals, gaps, contradictions);
    const blockingBlockers = evaluated.blockers.filter((blocker) => blocker.severity === 'blocking');
    const decision = blockingBlockers.length > 0
      ? 'STOP_BLOCKED'
      : evaluated.trace.every((entry) => entry.passed) ? 'STOP_ALLOWED' : 'CONTINUE';
    const momentum = snapshots.length < 2
      ? null
      : Object.fromEntries(Object.keys(snapshots[snapshots.length - 1].metrics || {}).flatMap((key) => {
          const latest = snapshots[snapshots.length - 1].metrics[key];
          const previous = snapshots[snapshots.length - 2].metrics[key];
          return typeof latest === 'number' && typeof previous === 'number' ? [[key, latest - previous]] : [];
        }));

    if (asBoolean(args.persistSnapshot) && args.iteration !== undefined) {
      db.createSnapshot({
        specFolder,
        loopType,
        sessionId,
        iteration: Number(args.iteration),
        metrics: { ...signals, nodeCount: stats.totalNodes, edgeCount: stats.totalEdges },
        nodeCount: stats.totalNodes,
        edgeCount: stats.totalEdges,
      });
    }

    const data = {
      decision,
      reason: decisionReason(decision, blockingBlockers, evaluated.trace),
      score,
      signals: signalsWithScore,
      blockers: evaluated.blockers,
      trace: evaluated.trace,
      momentum,
      namespace: ns,
      scopeMode: 'session',
      notes: ['Convergence signals were computed from the session-scoped subgraph only.'],
      snapshotPersistence: asBoolean(args.persistSnapshot) ? 'persisted' : 'not_requested',
      nodeCount: stats.totalNodes,
      edgeCount: stats.totalEdges,
      lastIteration: stats.lastIteration,
    };
    jsonOut({
      status: 'ok',
      data,
      graph_decision: decision,
      graph_decision_json: JSON.stringify(decision),
      graph_signals_json: signalsWithScore,
      graph_blockers_json: evaluated.blockers,
      graph_blockers_csv: blockersCsv(evaluated.blockers),
      graph_stop_blocked: decision === 'STOP_BLOCKED',
      graph_trace_json: evaluated.trace,
      graph_convergence_score: score,
    });
  } finally {
    db?.closeDb();
  }
}

main().catch((err) => {
  const code = classifyExitCode(err);
  jsonOut({ status: 'error', error: err instanceof Error ? err.message : String(err), code: err && err.code ? err.code : 'SCRIPT_ERROR' });
  if (code === 1) {
    process.stderr.write(JSON.stringify({ error: err instanceof Error ? err.message : String(err), stack: err && err.stack }) + '\n');
  }
  process.exit(code);
});

#!/usr/bin/env node

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║ Deep-Loop Runtime — Upsert Entrypoint                                    ║
// ╠══════════════════════════════════════════════════════════════════════════╣
// ║ Input:  CLI args (--spec-folder, --loop-type, --session-id, --nodes,     ║
// ║         --edges, or --events).                                           ║
// ║ Output: JSON to stdout.                                                  ║
// ║ Exit:   0=ok, 1=script error, 2=DB error, 3=input validation error.     ║
// ╚══════════════════════════════════════════════════════════════════════════╝

'use strict';

// ─────────────────────────────────────────────────────────────────────────────
// 1. IMPORTS
// ─────────────────────────────────────────────────────────────────────────────

const fs = require('node:fs');
const path = require('node:path');
const { spawnSync } = require('node:child_process');

const {
  acquireWriterLock,
  classifyExitCode,
  installSignalHandlers,
  maybeThrowTestFault,
  sleepSync,
  validateNamespaceValue,
} = require('./lib/cli-guards.cjs');

// ─────────────────────────────────────────────────────────────────────────────
// 2. CONSTANTS
// ─────────────────────────────────────────────────────────────────────────────

const TSX_LOADER = path.resolve(__dirname, '..', '..', 'system-spec-kit', 'scripts', 'node_modules', 'tsx', 'dist', 'loader.mjs');

if (process.env.DEEP_LOOP_TSX_LOADED !== '1') {
  const child = spawnSync(process.execPath, ['--import', TSX_LOADER, __filename, ...process.argv.slice(2)], {
    cwd: process.cwd(),
    env: { ...process.env, DEEP_LOOP_TSX_LOADED: '1' },
    input: process.stdin.isTTY ? undefined : fs.readFileSync(0),
    encoding: 'utf8',
  });
  if (child.stdout) process.stdout.write(child.stdout);
  if (child.stderr) process.stderr.write(child.stderr);
  process.exit(child.status === null ? 1 : child.status);
}

// ─────────────────────────────────────────────────────────────────────────────
// 3. HELPERS
// ─────────────────────────────────────────────────────────────────────────────

function parseArgs(argv = process.argv.slice(2)) {
  const args = {};
  for (let i = 0; i < argv.length; i += 1) {
    const token = argv[i];
    if (!token.startsWith('--')) throw inputError(`Unexpected positional argument: ${token}`);
    const key = token.slice(2).replace(/-([a-z])/g, (_, c) => c.toUpperCase());
    const next = argv[i + 1];
    if (next === undefined || next.startsWith('--')) args[key] = true;
    else {
      args[key] = next;
      i += 1;
    }
  }
  return args;
}

function inputError(message) {
  const err = new Error(message);
  err.code = 'INPUT_VALIDATION';
  return err;
}

function ensureString(args, key) {
  if (!args[key] || typeof args[key] !== 'string') throw inputError(`${key} is required`);
  return args[key];
}

function parseJsonValue(value, fallback, label) {
  if (value === undefined || value === null || value === '') return fallback;
  if (typeof value !== 'string') return value;
  try {
    return JSON.parse(value);
  } catch (err) {
    throw inputError(`${label} must be valid JSON: ${err instanceof Error ? err.message : String(err)}`);
  }
}

function readEvents(arg) {
  if (!arg) return null;
  const raw = arg === '-' ? fs.readFileSync(0, 'utf8') : fs.readFileSync(path.resolve(arg), 'utf8');
  return parseJsonValue(raw, [], 'events');
}

function jsonOut(payload) {
  process.stdout.write(`${JSON.stringify(payload)}\n`);
}

// ─────────────────────────────────────────────────────────────────────────────
// 4. CORE LOGIC
// ─────────────────────────────────────────────────────────────────────────────

async function main() {
  const args = parseArgs();
  const specFolder = validateNamespaceValue(ensureString(args, 'specFolder'), 'specFolder', inputError);
  const loopType = ensureString(args, 'loopType');
  const sessionId = validateNamespaceValue(ensureString(args, 'sessionId'), 'sessionId', inputError);
  if (loopType !== 'research' && loopType !== 'review' && loopType !== 'council' && loopType !== 'context') throw inputError('loopType must be "research", "review", "council", or "context"');

  let db = null;
  let releaseWriterLock = null;
  const cleanup = () => {
    releaseWriterLock?.();
    releaseWriterLock = null;
    db?.closeDb();
  };
  try {
    const isCouncil = loopType === 'council';
    db = isCouncil
      ? await import('../lib/council/council-graph-db.ts')
      : await import('../lib/coverage-graph/coverage-graph-db.ts');
    installSignalHandlers(cleanup);
    maybeThrowTestFault();
    const events = readEvents(args.events);
    const rawNodes = events
      ? events.filter((event) => event && (event.type === 'node' || event.nodeKind || event.kind))
      : parseJsonValue(args.nodes, [], 'nodes');
    const rawEdges = events
      ? events.filter((event) => event && (event.type === 'edge' || event.source || event.sourceId || event.target || event.targetId))
      : parseJsonValue(args.edges, [], 'edges');
    if (!Array.isArray(rawNodes) || !Array.isArray(rawEdges)) throw inputError('nodes and edges must be JSON arrays');
    if (rawNodes.length === 0 && rawEdges.length === 0) {
      if (isCouncil) {
        const namespace = { specFolder, loopType, sessionId };
        jsonOut({
          status: 'ok',
          data: {
            insertedNodes: 0,
            insertedEdges: 0,
            rejectedEdges: 0,
            rejectedSelfLoops: [],
            noOp: true,
            namespace,
            sourceOfTruth: 'derived_from_ai_council_artifacts',
          },
          graph_nodes_json: [],
          graph_edges_json: [],
          graph_upsert_event_count: 0,
        });
        return;
      }
      throw inputError('At least one node or edge must be provided');
    }

    const validationErrors = [];
    const rejectedSelfLoops = [];
    const nodes = [];
    const edges = [];

    for (const n of rawNodes) {
      const kind = String(n.kind || n.nodeKind || n.type || '').toUpperCase();
      if (!n.id || typeof n.id !== 'string') {
        validationErrors.push('Node missing required id');
        continue;
      }
      const validKinds = isCouncil ? db.VALID_KINDS : db.VALID_KINDS[loopType];
      if (!validKinds.includes(kind)) {
        validationErrors.push(`Invalid node kind "${kind}" for loop type "${loopType}". Valid: ${validKinds.join(', ')}`);
        continue;
      }
      const name = n.name || n.label || n.id;
      const baseNode = {
        id: n.id,
        specFolder,
        sessionId,
        kind,
        name,
        metadata: n.metadata,
      };
      nodes.push(isCouncil
        ? {
            ...baseNode,
            artifactPath: n.artifactPath,
            contentHash: n.contentHash,
            roundId: n.roundId,
          }
        : {
            ...baseNode,
            loopType,
            contentHash: n.contentHash,
            iteration: n.iteration,
          });
    }

    for (const e of rawEdges) {
      const sourceId = e.sourceId || e.source;
      const targetId = e.targetId || e.target;
      const relation = String(e.relation || '').toUpperCase();
      if (!e.id || typeof e.id !== 'string') {
        validationErrors.push('Edge missing required id');
        continue;
      }
      if (!sourceId || !targetId) {
        validationErrors.push(`Edge "${e.id}" missing sourceId or targetId`);
        continue;
      }
      if (sourceId === targetId) {
        rejectedSelfLoops.push(e.id);
        continue;
      }
      const validRelations = isCouncil ? db.VALID_RELATIONS : db.VALID_RELATIONS[loopType];
      if (!validRelations.includes(relation)) {
        validationErrors.push(`Invalid relation "${relation}" for loop type "${loopType}". Valid: ${validRelations.join(', ')}`);
        continue;
      }
      const baseEdge = {
        id: e.id,
        specFolder,
        sessionId,
        sourceId,
        targetId,
        relation,
        weight: db.clampWeight(e.weight ?? 1.0),
        metadata: e.metadata,
      };
      edges.push(isCouncil
        ? {
            ...baseEdge,
            artifactPath: e.artifactPath,
          }
        : {
            ...baseEdge,
            loopType,
          });
    }

    const storageDir = isCouncil ? db.COUNCIL_GRAPH_STORAGE_DIR : db.COVERAGE_GRAPH_DATABASE_DIR;
    releaseWriterLock = acquireWriterLock(path.join(storageDir, isCouncil ? '.council-graph-writer.lock' : '.deep-loop-graph-writer.lock'));
    sleepSync(Number(process.env.DEEP_LOOP_SCRIPT_LOCK_HOLD_MS || 0));
    const result = db.batchUpsert(nodes, edges);
    const namespace = { specFolder, loopType, sessionId };
    const data = {
      insertedNodes: result.insertedNodes,
      insertedEdges: result.insertedEdges,
      rejectedEdges: result.rejectedEdges,
      rejectedSelfLoops,
      validationErrors: validationErrors.length > 0 ? validationErrors : undefined,
      namespace,
      ...(isCouncil ? { sourceOfTruth: 'derived_from_ai_council_artifacts' } : {}),
    };
    jsonOut({
      status: 'ok',
      data,
      graph_nodes_json: nodes,
      graph_edges_json: edges,
      graph_upsert_event_count: nodes.length + edges.length,
    });
  } finally {
    cleanup();
  }
}

main().catch((err) => {
  const code = classifyExitCode(err);
  jsonOut({ status: 'error', error: err instanceof Error ? err.message : String(err), code: err && err.code ? err.code : 'SCRIPT_ERROR' });
  if (code === 1) process.stderr.write(JSON.stringify({ error: err instanceof Error ? err.message : String(err), stack: err && err.stack }) + '\n');
  process.exit(code);
});

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║ Council Multi-Seat Dispatch                                              ║
// ╚══════════════════════════════════════════════════════════════════════════╝

'use strict';

// ─────────────────────────────────────────────────────────────────────────────
// 1. IMPORTS
// ─────────────────────────────────────────────────────────────────────────────

// ─────────────────────────────────────────────────────────────────────────────
// 2. CONSTANTS
// ─────────────────────────────────────────────────────────────────────────────

// ─────────────────────────────────────────────────────────────────────────────
// 3. HELPERS
// ─────────────────────────────────────────────────────────────────────────────

function isRecord(value) {
  return value !== null && typeof value === 'object' && !Array.isArray(value);
}

function normalizeSeat(seat, index) {
  if (typeof seat === 'string') {
    return { id: seat, input: { id: seat } };
  }
  if (!isRecord(seat)) {
    throw new TypeError(`seat at index ${index} must be a string or object`);
  }
  if (typeof seat.id !== 'string' || seat.id.trim() === '') {
    throw new TypeError(`seat at index ${index} must include a non-empty id`);
  }
  return { id: seat.id, input: seat };
}

function normalizeRoundId(roundId) {
  if (typeof roundId !== 'string' || roundId.trim() === '') {
    throw new TypeError('roundId must be a non-empty string');
  }
  return roundId;
}

function normalizeTimestamp(value) {
  if (value instanceof Date) {
    return value.toISOString();
  }
  if (typeof value === 'string' && value.trim() !== '') {
    return value;
  }
  return new Date().toISOString();
}

// ─────────────────────────────────────────────────────────────────────────────
// 4. CORE LOGIC
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Dispatch a single council seat and capture its result or error.
 *
 * Wraps the seat-specific dispatch function and records timing,
 * status (fulfilled/rejected), and any error details so the
 * multi-seat dispatcher can aggregate per-round results.
 *
 * @param {Object} params - Seat dispatch parameters.
 * @param {Object} params.seat - Normalized seat descriptor with id
 *   and input.
 * @param {number} params.index - Zero-based seat index within the round.
 * @param {string} params.roundId - Normalized round identifier.
 * @param {Function} params.dispatchSeat - Async function that accepts
 *   (seatInput, context) and returns the seat's output.
 * @param {Object} params.context - Arbitrary context forwarded to
 *   dispatchSeat.
 * @param {Function} params.now - Callable returning a Date or ISO
 *   timestamp for timing.
 * @returns {Promise<Object>} Per-seat result with seat_id, status,
 *   started_at_iso, completed_at_iso, duration_ms, and
 *   output or error.
 */
async function settleSeat({ seat, index, roundId, dispatchSeat, context, now }) {
  const startedAtIso = normalizeTimestamp(now());
  const startedAtMs = Date.now();
  try {
    const output = await dispatchSeat(seat.input, { roundId, seatIndex: index, context });
    return {
      seat_id: seat.id,
      status: 'fulfilled',
      started_at_iso: startedAtIso,
      completed_at_iso: normalizeTimestamp(now()),
      duration_ms: Math.max(0, Date.now() - startedAtMs),
      output,
    };
  } catch (error) {
    return {
      seat_id: seat.id,
      status: 'rejected',
      started_at_iso: startedAtIso,
      completed_at_iso: normalizeTimestamp(now()),
      duration_ms: Math.max(0, Date.now() - startedAtMs),
      error: {
        name: error && error.name ? String(error.name) : 'Error',
        message: error && error.message ? String(error.message) : String(error),
      },
    };
  }
}

/**
 * Dispatch all council seats for a single deliberation round in parallel.
 *
 * Normalizes inputs, dispatches each seat concurrently via
 * Promise.all, and returns an aggregated round result with per-seat
 * outcomes and a summary (total / succeeded / failed / all_failed).
 *
 * @param {Object} options - Dispatch configuration.
 * @param {string} options.roundId - Round identifier (non-empty string).
 * @param {Array<string|Object>} options.seats - Array of seat
 *   descriptors (string IDs or objects with id and input).
 * @param {Function} options.dispatchSeat - Async dispatch function
 *   invoked per seat.
 * @param {Object} [options.context={}] - Arbitrary context forwarded
 *   to each seat dispatch.
 * @param {Function} [options.now] - Callable returning a Date or ISO
 *   timestamp (default: () => new Date()).
 * @returns {Promise<Object>} Round result with round_id,
 *   started_at_iso, completed_at_iso, results array, and summary.
 * @throws {TypeError} If options is not an object, roundId is invalid,
 *   seats is empty, or dispatchSeat is not a function.
 */
async function dispatchCouncilSeats(options) {
  if (!isRecord(options)) {
    throw new TypeError('dispatchCouncilSeats options must be an object');
  }
  const roundId = normalizeRoundId(options.roundId);
  if (!Array.isArray(options.seats) || options.seats.length === 0) {
    throw new TypeError('seats must be a non-empty array');
  }
  if (typeof options.dispatchSeat !== 'function') {
    throw new TypeError('dispatchSeat must be a function');
  }

  const now = typeof options.now === 'function' ? options.now : () => new Date();
  const seats = options.seats.map(normalizeSeat);
  const startedAtIso = normalizeTimestamp(now());
  const results = await Promise.all(
    seats.map((seat, index) => settleSeat({
      seat,
      index,
      roundId,
      dispatchSeat: options.dispatchSeat,
      context: options.context || {},
      now,
    })),
  );
  const completedAtIso = normalizeTimestamp(now());
  const succeeded = results.filter((result) => result.status === 'fulfilled').length;
  const failed = results.length - succeeded;

  return {
    round_id: roundId,
    started_at_iso: startedAtIso,
    completed_at_iso: completedAtIso,
    results,
    summary: {
      total: results.length,
      succeeded,
      failed,
      all_failed: failed === results.length,
    },
  };
}

// ─────────────────────────────────────────────────────────────────────────────
// 5. EXPORTS
// ─────────────────────────────────────────────────────────────────────────────

module.exports = {
  dispatchCouncilSeats,
};

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║ Council Graph Convergence                                                ║
// ╚══════════════════════════════════════════════════════════════════════════╝
'use strict';

// ─────────────────────────────────────────────────────────────────────────────
// 1. CONSTANTS
// ─────────────────────────────────────────────────────────────────────────────

const THRESHOLDS = {
  agreementRatio: 0.67,
  dissentDensity: 0.25,
  evidenceDepth: 1.0,
  unresolvedCriticalDisagreements: 0,
  decisionConfidence: 0.65,
};

// ─────────────────────────────────────────────────────────────────────────────
// 2. HELPERS
// ─────────────────────────────────────────────────────────────────────────────

async function loadCouncilModules() {
  const db = await import('./council-graph-db.ts');
  const query = await import('./council-graph-query.ts');
  return { db, query };
}

function clamp(value) {
  return Math.max(0, Math.min(1, value));
}

function round(value) {
  return Math.round(value * 1000) / 1000;
}

function blockersCsv(blockers) {
  return blockers
    .filter((blocker) => blocker && blocker.severity === 'blocking')
    .map((blocker) => `${blocker.type}:${blocker.count}`)
    .join(',');
}

function buildTrace(signals) {
  return [
    { signal: 'agreementRatio', value: signals.agreementRatio, threshold: THRESHOLDS.agreementRatio, passed: signals.agreementRatio >= THRESHOLDS.agreementRatio },
    { signal: 'dissentDensity', value: signals.dissentDensity, threshold: THRESHOLDS.dissentDensity, passed: signals.dissentDensity <= THRESHOLDS.dissentDensity },
    { signal: 'evidenceDepth', value: signals.evidenceDepth, threshold: THRESHOLDS.evidenceDepth, passed: signals.evidenceDepth >= THRESHOLDS.evidenceDepth },
    { signal: 'unresolvedCriticalDisagreements', value: signals.unresolvedCriticalDisagreements, threshold: THRESHOLDS.unresolvedCriticalDisagreements, passed: signals.unresolvedCriticalDisagreements === 0 },
    { signal: 'decisionConfidence', value: signals.decisionConfidence, threshold: THRESHOLDS.decisionConfidence, passed: signals.decisionConfidence >= THRESHOLDS.decisionConfidence },
  ];
}

function buildReason(decision, blockingCount, failedSignals) {
  if (decision === 'STOP_BLOCKED') return `${blockingCount} blocking council convergence issue(s) remain`;
  if (decision === 'STOP_ALLOWED') return 'Council graph signals meet convergence thresholds';
  return `Council graph has not converged; failing signals: ${failedSignals.join(', ') || 'none'}`;
}

function bridgePayload(data) {
  return {
    status: 'ok',
    data,
    graph_decision: data.decision,
    graph_decision_json: JSON.stringify(data.decision),
    graph_signals_json: data.signals ?? {},
    graph_blockers_json: data.blockers ?? [],
    graph_blockers_csv: blockersCsv(data.blockers ?? []),
    graph_stop_blocked: data.decision === 'STOP_BLOCKED',
    graph_trace_json: data.trace ?? [],
    graph_convergence_score: data.score ?? data.signals?.score ?? 0,
  };
}

// ─────────────────────────────────────────────────────────────────────────────
// 3. CORE LOGIC
// ─────────────────────────────────────────────────────────────────────────────

async function computeCouncilSignals(ns) {
  const { db, query } = await loadCouncilModules();
  const councilNs = { specFolder: ns.specFolder, sessionId: ns.sessionId };
  const nodes = db.getNodes(councilNs);
  const edges = db.getEdges(councilNs);
  const decisions = nodes.filter((node) => node.kind === 'DECISION' || node.kind === 'RECOMMENDATION');
  const agreementEdges = edges.filter((edge) => edge.relation === 'AGREES_WITH').length;
  const dissentEdges = edges.filter((edge) => edge.relation === 'CONTRADICTS' || edge.relation === 'ESCALATES').length;
  const agreementDenominator = agreementEdges + dissentEdges;
  const agreementRatio = agreementDenominator === 0 ? 0 : agreementEdges / agreementDenominator;
  const dissentDensity = edges.length === 0 ? 0 : dissentEdges / edges.length;
  const evidenceEdges = edges.filter((edge) => edge.relation === 'EVIDENCE_FOR' || edge.relation === 'SUPPORTS').length;
  const evidenceDepth = decisions.length === 0 ? 0 : evidenceEdges / decisions.length;
  const blockerData = query.findConvergenceBlockers(councilNs);
  const decisionConfidence = decisions.length === 0
    ? 0
    : decisions.reduce((sum, node) => sum + query.confidence(node.metadata), 0) / decisions.length;

  const normalizedEvidenceDepth = Math.min(evidenceDepth / 2, 1);
  const score = round(
    clamp(agreementRatio) * 0.25
    + (1 - clamp(dissentDensity)) * 0.20
    + normalizedEvidenceDepth * 0.20
    + (blockerData.unresolvedCriticalDisagreements.length === 0 ? 1 : 0) * 0.20
    + clamp(decisionConfidence) * 0.15,
  );

  return {
    agreementRatio: round(agreementRatio),
    dissentDensity: round(dissentDensity),
    evidenceDepth: round(evidenceDepth),
    unresolvedCriticalDisagreements: blockerData.unresolvedCriticalDisagreements.length,
    decisionConfidence: round(decisionConfidence),
    score,
  };
}

async function buildBlockers(ns, signals) {
  const { query } = await loadCouncilModules();
  const councilNs = { specFolder: ns.specFolder, sessionId: ns.sessionId };
  const blockerData = query.findConvergenceBlockers(councilNs);
  const blockers = [];
  if (signals.unresolvedCriticalDisagreements > 0) {
    blockers.push({
      type: 'unresolved_critical_disagreements',
      severity: 'blocking',
      count: signals.unresolvedCriticalDisagreements,
      nodes: blockerData.unresolvedCriticalDisagreements,
    });
  }
  if (blockerData.unsupportedDecisions.length > 0) {
    blockers.push({
      type: 'unsupported_decisions',
      severity: 'warning',
      count: blockerData.unsupportedDecisions.length,
      nodes: blockerData.unsupportedDecisions,
    });
  }
  if (blockerData.lowConfidenceDecisions.length > 0) {
    blockers.push({
      type: 'low_confidence_decisions',
      severity: 'warning',
      count: blockerData.lowConfidenceDecisions.length,
      nodes: blockerData.lowConfidenceDecisions,
    });
  }
  return blockers;
}

async function evaluateCouncilConvergence(ns, options = {}) {
  const { db } = await loadCouncilModules();
  const councilNs = { specFolder: ns.specFolder, sessionId: ns.sessionId };
  const stats = db.getStats(ns.specFolder, ns.sessionId);

  if (stats.totalNodes === 0) {
    return {
      decision: 'STOP_BLOCKED',
      reason: 'Council graph is empty; derived graph data is required before convergence can be assessed',
      signals: null,
      blockers: [{ type: 'empty_graph', severity: 'blocking', count: 1 }],
      trace: [],
      namespace: ns,
      scopeMode: 'session',
      readiness: 'empty',
      sourceOfTruth: 'derived_from_ai_council_artifacts',
      nodeCount: 0,
      edgeCount: 0,
      score: 0,
    };
  }

  const signals = await computeCouncilSignals(ns);
  const blockers = await buildBlockers(ns, signals);
  const trace = buildTrace(signals);
  const blocking = blockers.filter((blocker) => blocker.severity === 'blocking');
  const decision = blocking.length > 0
    ? 'STOP_BLOCKED'
    : trace.every((entry) => entry.passed) ? 'STOP_ALLOWED' : 'CONTINUE';
  const reason = buildReason(
    decision,
    blocking.length,
    trace.filter((entry) => !entry.passed).map((entry) => entry.signal),
  );

  if (options.persistSnapshot) {
    db.createSnapshot({
      specFolder: ns.specFolder,
      sessionId: ns.sessionId,
      roundId: options.roundId,
      metrics: { ...signals },
      nodeCount: stats.totalNodes,
      edgeCount: stats.totalEdges,
    });
  }

  return {
    decision,
    reason,
    score: signals.score,
    signals,
    blockers,
    trace,
    namespace: ns,
    scopeMode: 'session',
    readiness: 'ready',
    sourceOfTruth: 'derived_from_ai_council_artifacts',
    snapshotPersistence: options.persistSnapshot ? 'persisted' : 'not_requested',
    nodeCount: stats.totalNodes,
    edgeCount: stats.totalEdges,
    snapshotCount: stats.snapshotCount,
  };
}

// ─────────────────────────────────────────────────────────────────────────────
// 4. EXPORTS
// ─────────────────────────────────────────────────────────────────────────────

module.exports = {
  THRESHOLDS,
  bridgePayload,
  computeCouncilSignals,
  evaluateCouncilConvergence,
};

